package keeper

import (
"encoding/hex"
"fmt"
"math/big"
"strings"

"github.com/ethereum/go-ethereum/common"
)

// V7ContractBytecode is the compiled bytecode of AequitasV7.sol (0.8.22, optimizer 200 runs).
// This is used to redeploy the contract after a DB reset — without this the node
// would fail with "no code at address" on every registration attempt.
// The contract was compiled from the AequitasV7.sol source on 2026-06-19.
const V7ContractBytecode = ""

// EnsureContractsDeployed deploys the V7 contract if missing from the DB.
// It forces nonce=0 for the deployer so the contract always lands at the
// same deterministic address (0xE832...) regardless of prior state.
func EnsureContractsDeployed(evm *EVMEngine, state *ChainState, deployerAddr string) {
v7Addr := strings.ToLower(V7_CONTRACT_ADDR)
existing, err := state.LoadContract(v7Addr)
if err == nil && len(existing) > 0 {
fmt.Printf("[DEPLOY] V7 contract already deployed at %s (%d bytes)\n", V7_CONTRACT_ADDR, len(existing))
return
}

fmt.Printf("[DEPLOY] V7 contract not found — deploying with forced nonce=0...\n")

bytecode, err := hex.DecodeString(V7ContractBytecode)
if err != nil {
fmt.Printf("[DEPLOY] ERROR: failed to decode bytecode: %v\n", err)
return
}

// ABI-encode constructor arg: BioVerifier address (32 bytes, left-padded)
bioVerifier := common.HexToAddress(BIO_VERIFIER_ADDR)
constructorArg := make([]byte, 32)
copy(constructorArg[12:], bioVerifier.Bytes())
deployBytecode := append(bytecode, constructorArg...)

// Force deployer nonce to 0 so CREATE produces the same address every time.
// The deterministic address from nonce=0 + deployer=0x0BE8... is 0xE832...
deployer := common.HexToAddress(deployerAddr)
deployerLow := strings.ToLower(deployer.Hex())
state.SaveNonce(deployerLow, 0)

contractAddr, _, deployErr := evm.DeployContract(deployer, deployBytecode, big.NewInt(0))
if deployErr != nil {
fmt.Printf("[DEPLOY] ERROR: deploy failed: %v\n", deployErr)
return
}

deployedLow := strings.ToLower(contractAddr.Hex())
fmt.Printf("[DEPLOY] Deployed at %s (expected %s)\n", deployedLow, v7Addr)

if deployedLow != v7Addr {
// Copy runtime code to expected address
runtime, loadErr := state.LoadContract(deployedLow)
if loadErr == nil && len(runtime) > 0 {
state.SaveContract(v7Addr, runtime, deployerAddr)
v7Common := common.HexToAddress(V7_CONTRACT_ADDR)
evm.SetCode(v7Common, runtime)
// Copy storage slots too
state.CopyContractStorage(deployedLow, v7Addr)
fmt.Printf("[DEPLOY] ✓ Copied runtime+storage to %s\n", V7_CONTRACT_ADDR)
}
} else {
fmt.Printf("[DEPLOY] ✓ V7 deployed at correct address %s\n", V7_CONTRACT_ADDR)
}
}
